urlset:

    {{ base_url }}
    weekly
    1.0


    {{ base_url }}about/
    monthly
    0.8


    {{ base_url }}projects/
    weekly
    0.8


    {{ base_url }}blog/
    weekly
    0.8


    {{ base_url }}vacancies/
    weekly
    0.7

{% for post in posts %}

    {{ base_url }}blog/{{ post.slug }}
    {{ post.updated_at.strftime('%Y-%m-%d') }}
    monthly
    0.6

{% endfor %}
{% for vacancy in vacancies %}

    {{ base_url }}vacancies/{{ vacancy.id }}
    {{ vacancy.created_at.strftime('%Y-%m-%d') }}
    monthly
    0.6

{% endfor %}
{% for project in projects %}

    {{ base_url }}projects/{{ project.slug }}
    monthly
    0.6

{% endfor %}
